sys_script_include.script:
var MedicineScripts = Class.create();
MedicineScripts.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
	checkAvailability : function(){
		var medicine = this.getParameter('sysparm_medicine');
		var quantity = this.getParameter('sysparm_quantity');

		if(medicine == '' || quantity == ''){
			return;
		}
		var gr = new GlideRecord('x_1971078_smart_0_medicine_inventory');

		if(gr.get(medicine)){
			if(gr.status == 'expired'){
				return false;
			}
			var total_qty = parseInt(gr.quantity);
			var qty = parseInt(quantity);
			if(qty <= total_qty){
				return true;
			}
		}
		return false;
	},
	getUnitPrice : function(){
		var medicine =  this.getParameter('sysparm_medicine');

		if(medicine == ''){
			return 0;
		} 
		var gr = new GlideRecord('x_1971078_smart_0_medicine_inventory');
		if(gr.get(medicine)){
			return gr.unit_price.toString();
		}
		return 0;

	},


    type: 'MedicineScripts'
});
